For Each Order EmpCod, MrkCod, MrkPedSku
	Where EmpCod = &EmPCod
	Where MrkCod = &MrkCod
	Where MrkPedSku = &MrkPedSku

	Do Case
		CAse MrkPedSts = 'X' //CANCELADO
			&MrkPedStsEnv = MarketplaceStatusPedido.CANCELADO //CANCELADO

		Case MrkPedSts = 'A' //PAGO

			Do CAse 
				Case MrkPedCod.IsEmpty() or MrkPedCod.IsNull()
					&MrkPedStsEnv = MarketplaceStatusPedido.GERAR_PEDIDO //GERAR PEDIDO

				Case (MrkNfeCod.IsEmpty() or MrkNfeCod.IsNull()) and (MrkPedEtqDtaHor.IsEmpty() or MrkPedEtqDtaHor.IsNull())
					&MrkPedStsEnv = MarketplaceStatusPedido.EMITIR_NOTA //EMITIR NOTA

				CAse MrkPedNfDtaHor.IsEmpty() or MrkPedNfDtaHor.IsNull() and (MrkPedEtqDtaHor.IsEmpty() or MrkPedEtqDtaHor.IsNull())
					&MrkPedStsEnv = MarketplaceStatusPedido.ENVIAR_NOTA //ENVIAR NOTA

				case MrkPedEtqDtaHor.IsEmpty() or MrkPedEtqDtaHor.IsNull()
					&MrkPedStsEnv = MarketplaceStatusPedido.GERAR_ETIQUETA //GERAR ETIQUETA

				case not MrkPedEtqDtaHor.IsEmpty() and not MrkPedEtqDtaHor.IsNull()
					&MrkPedStsEnv = MarketplaceStatusPedido.DESPACHAR_PRODUTO //DESPACHAR PRODUTO

				CAse not MrkPedDspDtaHor.IsEmpty() and not MrkPedDspDtaHor.IsNull()
					&MrkPedStsEnv = MarketplaceStatusPedido.EM_TRANSPORTE //EM TRANSPORTE

			EndCase
	EndCase	
	MrkPedStsEnv = &MrkPedStsEnv

EndFor


